import "./Footer.css";

/**
 * Footer
 * Minimal brand strip at the bottom of the page.
 */
export default function Footer() {
  const year = new Date().getFullYear();

  return (
    <footer className="footer">
      <span className="footer__brand">
        Shot on iPhone <em>in B&amp;W</em>
      </span>
      <span className="footer__info">
        © {year} · All frames captured on iPhone 15 Pro
      </span>
    </footer>
  );
}
